import{_ as a,o as t,c as r,a4 as o}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"Labradorescence (Spectrolite)","description":"","frontmatter":{"title":"Labradorescence (Spectrolite)","phenomenon":"labradorescence"},"headers":[],"relativePath":"optical-phenomena/labradorescence.md","filePath":"optical-phenomena/labradorescence.md","lastUpdated":1784177547000}'),i={name:"optical-phenomena/labradorescence.md"};function n(l,e,s,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="labradorescence-spectrolite" tabindex="-1">Labradorescence (Spectrolite) <a class="header-anchor" href="#labradorescence-spectrolite" aria-label="Permalink to &quot;Labradorescence (Spectrolite)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The signature effect of labradorite (plagioclase feldspar series). On a cabochon cut, alternating nanoscale layers or compositional striations reflect and interfere with light, producing vivid flashes of blue, green, orange, and gold with a metallic sheen. The colors shift continuously with viewing angle — a holographic quality. The mechanism is similar to adularescence but with greater compositional variation and refractive-index contrast between layers, producing more saturated colors. The most famous example is Finnish Spectrolite.</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Compositional lamellar structure: labradorite&#39;s anorthite (CaAl₂Si₂O₈) and albite (NaAlSi₃O₈) sub-layers alternate with thicknesses of ~50–250 nm. Refractive-index contrasts between layers (typically 0.005–0.012) fall in the range needed for strong selective interference with visible light. As viewing angle changes, the reflected wavelength shifts, producing angle-dependent color variation.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Host</th><th>Colors</th></tr></thead><tbody><tr><td>Labradorite / 拉长石</td><td>Plagioclase</td><td>blue-green dominant</td></tr><tr><td>Spectrolite / 光谱石</td><td>Plagioclase</td><td>full spectrum (Finland origin)</td></tr><tr><td>Andesine-Labradorite / 安山-拉长石</td><td>Plagioclase</td><td>green to red</td></tr><tr><td>Spectrolite (Madagascar)</td><td>Plagioclase</td><td>vivid blue-green</td></tr></tbody></table><p><em>See the <a href="./intro.html">optical phenomena overview</a>.</em></p>',8)])])}const b=a(i,[["render",n]]);export{m as __pageData,b as default};
